import fs from 'node:fs';
import path from 'node:path';
import { compile } from './packages/svelte/src/compiler/index.js';
const tmp = process.argv[2];
const source = `<script>
	const value = await "value";
</script>

{#snippet valueSnippet()}
	{value}
{/snippet}

{@render valueSnippet()}`;
const { js } = compile(source, { generate: 'client', dev: true, filename: 'Repro.svelte', experimental: { async: true } });
fs.writeFileSync(path.join(tmp, 'Repro.mjs'), js.code);
fs.writeFileSync(path.join(tmp, 'runner.mjs'), `
import { JSDOM } from 'jsdom';
const dom = new JSDOM('<!doctype html><div id="target"></div>', { url: 'http://localhost' });
globalThis.window = dom.window;
globalThis.document = dom.window.document;
globalThis.Node = dom.window.Node;
globalThis.Text = dom.window.Text;
globalThis.Element = dom.window.Element;
globalThis.HTMLElement = dom.window.HTMLElement;
globalThis.MutationObserver = dom.window.MutationObserver;
const errors = [];
process.on('unhandledRejection', (e) => { errors.push(e); });
const { mount, tick } = await import('svelte');
const { default: Repro } = await import('./Repro.mjs');
mount(Repro, { target: document.getElementById('target') });
await new Promise((r) => setTimeout(r, 20));
await tick();
console.log('html:', document.getElementById('target').innerHTML);
console.log('errors:', errors.map((e) => String(e && (e.stack || e.message || e))));
if (!errors.some((e) => String(e && (e.stack || e.message || e)).includes('value is not defined'))) {
  process.exitCode = 2;
}
`);
EOF
